const items = $input.all();
let result = [];

let telegramData = {};
try {
  telegramData = $('Telegram Trigger').first().json || {};
} catch (e) {}

// ── Helpers ──────────────────────────────────────────────────────

// Normaliza texto: minúsculas + sin acentos
const norm = (s) => s.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();

// Convierte a número decimal (acepta comas como decimal y quita %)
const toNum = (val) => {
  if (!val) return null;
  const n = parseFloat(val.toString().replace(/%/g, '').replace(',', '.').trim());
  return isNaN(n) ? null : n;
};

// Convierte a entero
const toInt = (val) => {
  if (!val) return null;
  const n = parseInt(val.toString().trim(), 10);
  return isNaN(n) ? null : n;
};

// Detecta separador dominante en una línea (tabulación o coma)
const detectSep = (line) => {
  const tabs   = (line.match(/\t/g) || []).length;
  const commas = (line.match(/,/g)  || []).length;
  return tabs >= commas ? '\t' : ',';
};

// Términos que sugieren que una línea es encabezado
const HEADER_TERMS = [
  "id", "elemento", "codigo", "partida", "subcodigo",
  "subpartida", "sub", "metrado", "fecha", "ejecucion",
  "avance", "porcentaje"
];
const looksLikeHeader = (line, sep) =>
  line.split(sep).some(col => HEADER_TERMS.some(t => norm(col).includes(t)));

// Busca el índice de una columna por términos clave (sobre headers ya separados)
const findIdx = (headers, terms) =>
  headers.findIndex(h => terms.some(t => norm(h).includes(t)));

// Construye un objeto fila a partir de valores y mapa de columnas
const buildFila = (cols, colMap) => {
  const get = (idx) => (idx !== -1 && cols[idx] !== undefined) ? cols[idx].trim() || null : null;
  return {
    "Id Elemento":       get(colMap.id),
    "Código de Partida": get(colMap.cod),
    "Subcódigo":         toInt(get(colMap.sub)),
    "Metrado Ejecutado": toNum(get(colMap.met)),
    "Fecha de Ejecución":get(colMap.fec),
    "% de Ejecución":    toNum(get(colMap.por))
  };
};

// Mapas posicionales fijos cuando NO hay encabezados detectables
// 1B → 3 columnas: Id Elemento | Fecha de Ejecución | % de Ejecución
const COLMAP_1B = { id: 0, cod: -1, sub: -1, met: -1, fec: 1, por: 2 };
// 2B → 5 columnas: Código de Partida | Subcódigo | Metrado | Fecha | %
const COLMAP_2B = { id: -1, cod: 0, sub: 1, met: 2, fec: 3, por: 4 };

// ── Procesamiento principal ───────────────────────────────────────
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  let buffer         = null;
  let msjError       = null;
  let filas          = [];
  let claseDetectada = "INVALIDO";

  // 1. Obtener datos binarios del archivo
  let binaryKey = null;
  if (item.binary && Object.keys(item.binary).length > 0) {
    binaryKey = Object.keys(item.binary)[0];
  }

  if (!binaryKey) {
    msjError = "No se encontró archivo adjunto.";
  } else {
    try {
      buffer = await this.helpers.getBinaryDataBuffer(i, binaryKey);
    } catch (e) {
      const binObj = item.binary[binaryKey];
      if (binObj && binObj.data) {
        buffer = (typeof binObj.data === 'string')
          ? Buffer.from(binObj.data, binObj.data.includes('\t') || binObj.data.includes('\n') ? 'utf-8' : 'base64')
          : binObj.data;
      }
    }
  }

  // 2. Procesar el contenido del archivo
  if (buffer) {
    try {
      // Detección de codificación
      let texto = buffer.toString('latin1');
      if (texto.includes('\u0000') || (buffer.length >= 2 && buffer[0] === 0xFF && buffer[1] === 0xFE)) {
        texto = buffer.toString('utf16le');
      }

      const lineas = texto.split(/\r?\n/).filter(l => l.trim() !== '');

      if (lineas.length < 1) {
        msjError = "El archivo está vacío.";
      } else {
        // Detectar separador a partir de la primera línea
        const sep = detectSep(lineas[0]);

        // ── ESTRATEGIA A: el archivo tiene encabezados reconocibles ──
        if (lineas.length >= 2 && looksLikeHeader(lineas[0], sep)) {

          const headers = lineas[0].split(sep).map(h => h.trim());
          const colMap  = {
            id:  findIdx(headers, ["id elemento", "elemento", "id"]),
            cod: findIdx(headers, ["codigo de partida", "codigo", "partida"]),
            sub: findIdx(headers, ["subcodigo", "subpartida", "sub"]),
            met: findIdx(headers, ["metrado ejecutado", "metrado"]),
            fec: findIdx(headers, ["fecha de ejecucion", "fecha ejecutada", "fecha ejecucion", "fecha"]),
            por: findIdx(headers, ["%", "porcentaje", "avance", "ejecucion"])
          };

          if      (colMap.id  !== -1) claseDetectada = "1B";
          else if (colMap.cod !== -1) claseDetectada = "2B";
          else msjError = "Encabezados no reconocidos: no se detectó 'Id Elemento' ni 'Código de Partida'.";

          if (!msjError) {
            for (let j = 1; j < lineas.length; j++) {
              const cols = lineas[j].split(sep);
              if (cols.length < 2) continue;
              filas.push(buildFila(cols, colMap));
            }
          }

        } else {
          // ── ESTRATEGIA B: sin encabezados — mapeo posicional por columnas ──
          // Se guía por la cantidad de columnas en la primera fila de datos.
          // 3 columnas → Clase 1B (Id Elemento, Fecha de Ejecución, % de Ejecución)
          // 5 columnas → Clase 2B (Código, Subcódigo, Metrado, Fecha, %)

          const numCols = lineas[0].split(sep).length;

          if (numCols === 3) {
            claseDetectada = "1B";
            for (let j = 0; j < lineas.length; j++) {
              const cols = lineas[j].split(sep);
              if (cols.length < 3) continue;
              filas.push(buildFila(cols, COLMAP_1B));
            }
          } else if (numCols === 5) {
            claseDetectada = "2B";
            for (let j = 0; j < lineas.length; j++) {
              const cols = lineas[j].split(sep);
              if (cols.length < 5) continue;
              filas.push(buildFila(cols, COLMAP_2B));
            }
          } else {
            msjError =
              `No se pudo determinar la clase del archivo: tiene ${numCols} columna(s). ` +
              `Se esperan 3 (Clase 1B: Id Elemento, Fecha, % Ejecución) ` +
              `o 5 (Clase 2B: Código de Partida, Subcódigo, Metrado, Fecha, % Ejecución).`;
          }
        }

        if (!msjError && filas.length === 0) {
          msjError = "El archivo no contiene filas de datos válidas. Verifica que use tabulaciones o comas como separador.";
        }
      }

    } catch (err) {
      msjError       = "Error de procesamiento: " + err.message;
      claseDetectada = "INVALIDO";
    }
  }

  result.push({
    json: {
      ...telegramData,
      "Clase":          msjError ? "INVALIDO" : claseDetectada,
      "tiene_foto":     false,
      "filas":          filas,
      "mensaje_error":  msjError
    }
  });
}

return result;

const item = $input.first().json;
const claseActual = item.Clase || item.clase || "INVALIDO";
return item.filas.map(f => ({ 
    json: { 
        clase: claseActual, 
        ...f, 
        url_foto: "No se registra" 
    } 
}));

// 1. Obtiene el texto de la IA y lo limpia de posibles marcadores de markdown
let textoIA = $input.first().json.text;
textoIA = textoIA.replace(/```json/g, '').replace(/```/g, '').trim();

// 2. Convierte el texto en objeto JSON
const datosParseados = JSON.parse(textoIA);

// 3. DETECCIÓN DE FOTO — lee directamente los metadatos de Telegram
//    Usamos .first() para garantizar que apunta al mensaje original del trigger
const mensajeTelegram = $('Telegram Trigger').first().json.message;

if (mensajeTelegram && mensajeTelegram.photo && mensajeTelegram.photo.length > 0) {
    datosParseados.tiene_foto = true;
} else {
    datosParseados.tiene_foto = false;
}

// 4. Retorna el JSON corregido
return [{ json: datosParseados }];

// Obtenemos todos los elementos entrantes (Los de Drive)
const itemsDrive = $input.all();
let resultados = [];

// Obtenemos los datos originales (Id Elemento, Metrado, etc.) del nodo anterior
// Usamos $items() que es la función más robusta en n8n
let itemsEstructura = [];
try {
    // IMPORTANTE: Este nombre debe coincidir exactamente con el de tu nodo
    itemsEstructura = $items("¿Se tiene una imagen?");
} catch (error) {
    console.log("No se ejecutó el nodo anterior o el nombre es distinto");
}

// Iteramos elemento por elemento, esto evita errores si n8n procesa varios a la vez
for (let i = 0; i < itemsDrive.length; i++) {

    // 1. Extraemos URL de la imagen
    let url_foto = "No se registra";
    if (itemsDrive[i].json && itemsDrive[i].json.webContentLink) {
        url_foto = itemsDrive[i].json.webContentLink;
    }

    // 2. Extraemos los datos del reporte original asociados a este mismo registro (índice 'i')
    // Si no los extrae de "¿Se tiene una imagen?", usa el mismo item actual como respaldo
    let datosFila = (itemsEstructura[i] && itemsEstructura[i].json) ? itemsEstructura[i].json : itemsDrive[i].json;

    // Extraemos la Clase y los 6 inputs de tus filas
    const clase = datosFila.Clase || datosFila.clase || "INVALIDO";
    const fila = (datosFila.filas && datosFila.filas.length > 0) ? datosFila.filas[0] : {};

    // 3. Estructuramos el resultado final plano (sin "filas")
    resultados.push({
        json: {
            clase: clase,
            ...fila,
            url_foto: url_foto
        }
    });
}

return resultados;
